import { Mark } from '../../mark/mark-utils';

function LegendContentWrapParser(spec) {
    let contentMark = Mark('group', '.zc-legend-content');
    contentMark.name = 'legend-content';
    contentMark.as = {
        x: 'background_x',
        y: 'background_y',
        width: 'background_width',
        height: 'background_height'
    };

    return contentMark;
}

export { LegendContentWrapParser };
